{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var centerX = GetFloat(parameters, "centerX", 0.5f);
var centerY = GetFloat(parameters, "centerY", 0.5f);
var strength = GetFloat(parameters, "intensity", 0.1f);
var quality = GetInt(parameters, "quality", 8);

var size = src.Width;
var cx = centerX * size;
var cy = centerY * size;
var result = new PixelBuffer(size, size);
var maxDist = MathF.Sqrt(cx * cx + cy * cy);
if (maxDist < 1f) maxDist = 1f;

result.ParallelForEachPixel((x, y) =>
{
    var dx = x - cx;
    var dy = y - cy;
    var dist = MathF.Sqrt(dx * dx + dy * dy);
    var blurAmount = (dist / maxDist) * strength * size;
    var samples = Math.Clamp((int)blurAmount, 2, quality);

    var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;

    for (var i = 0; i < samples; i++)
    {
        var t = (i / (float)(samples - 1)) * blurAmount;
        var sx = cx + (x - cx) * (1f - t / Math.Max(dist, 1f));
        var sy = cy + (y - cy) * (1f - t / Math.Max(dist, 1f));
        var (pr, pg, pb, pa) = src.GetPixelWrapped((int)MathF.Round(sx), (int)MathF.Round(sy));
        sumR += pr; sumG += pg; sumB += pb; sumA += pa;
    }

    var inv = 1f / samples;
    result.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
});

return result;
}
